def _money(value: Decimal) -> Decimal:
    return value.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)


def validate_cart_items(cart_items: List[CartItem]) -> Decimal:
    if not cart_items:
        raise ValidationError("Cart is empty.")
    subtotal = Decimal("0")
    for item in cart_items:
        if not item.sku or not item.name:
            raise ValidationError("Each cart item must have a SKU and name.")
        if item.quantity <= 0:
            raise ValidationError(f"Invalid quantity for item {item.sku}.")
        if item.unit_price < 0:
            raise ValidationError(f"Invalid unit price for item {item.sku}.")
        subtotal += item.line_total()
    return _money(subtotal)


def validate_discount_permission(user: User, discount: DiscountCode) -> None:
    if discount.admin_only and not user.is_admin:
        raise PermissionError(f"Discount code {discount.code} is admin-only.")
    if discount.allowed_tiers is not None and user.tier not in discount.allowed_tiers:
        raise PermissionError(f"Discount code {discount.code} is not available for tier {user.tier}.")


def apply_discount_codes(
    user: User,
    subtotal: Decimal,
    discount_codes: Optional[List[DiscountCode]] = None,
) -> Dict[str, Any]:
    discount_codes = discount_codes or []
    discount_total = Decimal("0")
    applied_codes = []

    for discount in discount_codes:
        validate_discount_permission(user, discount)
        code_discount = Decimal("0")
        if discount.percent_off > 0:
            code_discount += subtotal * (discount.percent_off / Decimal("100"))
        if discount.amount_off > 0:
            code_discount += discount.amount_off
        code_discount = min(code_discount, subtotal - discount_total)
        code_discount = _money(max(code_discount, Decimal("0")))
        discount_total += code_discount
        applied_codes.append(
            {
                "code": discount.code,
                "discount": code_discount,
            }
        )

    discount_total = min(discount_total, subtotal)
    return {
        "discount_total": _money(discount_total),
        "applied_codes": applied_codes,
        "discounted_subtotal": _money(subtotal - discount_total),
    }


def calculate_tax(amount: Decimal, tax_rate: Decimal) -> Decimal:
    if tax_rate < 0:
        raise ValidationError("Tax rate cannot be negative.")
    return _money(amount * (tax_rate / Decimal("100")))


def process_payment(user: User, amount_due: Decimal, payment_method: Dict[str, Any]) -> PaymentResult:
    if amount_due < 0:
        raise PaymentError("Amount due cannot be negative.")
    if amount_due == 0:
        return PaymentResult(success=True, transaction_id="FREE-ORDER", message="No payment required.")
    if not payment_method.get("token"):
        raise PaymentError("Missing payment token.")
    transaction_id = f"TXN-{user.user_id}-{payment_method['token']}"
    return PaymentResult(success=True, transaction_id=transaction_id, message="Payment processed successfully.")


def create_order_record(
    user: User,
    cart_items: List[CartItem],
    subtotal: Decimal,
    discount_total: Decimal,
    tax_total: Decimal,
    total: Decimal,
    discount_code: Optional[str],
    payment: PaymentResult,
) -> OrderRecord:
    order_id = f"ORD-{user.user_id}-{payment.transaction_id or 'PENDING'}"
    items = [
        {
            "sku": item.sku,
            "name": item.name,
            "unit_price": str(_money(item.unit_price)),
            "quantity": item.quantity,
            "line_total": str(item.line_total()),
        }
        for item in cart_items
    ]
    return OrderRecord(
        order_id=order_id,
        user_id=user.user_id,
        items=items,
        subtotal=_money(subtotal),
        discount_total=_money(discount_total),
        tax_total=_money(tax_total),
        total=_money(total),
        discount_code=discount_code,
        payment_transaction_id=payment.transaction_id,
    )


def checkout(
    user: User,
    cart_items: List[CartItem],
    discount_codes: Optional[List[DiscountCode]] = None,
    tax_rate: Decimal = Decimal("0"),
    payment_method: Optional[Dict[str, Any]] = None,
) -> CheckoutResult:
    payment_method = payment_method or {}

    subtotal = validate_cart_items(cart_items)

    discount_result = apply_discount_codes(user, subtotal, discount_codes)
    discounted_subtotal = discount_result["discounted_subtotal"]
    discount_total = discount_result["discount_total"]

    tax_total = calculate_tax(discounted_subtotal, tax_rate)
    total = _money(discounted_subtotal + tax_total)

    payment = process_payment(user, total, payment_method)

    order = create_order_record(
        user=user,
        cart_items=cart_items,
        subtotal=subtotal,
        discount_total=discount_total,
        tax_total=tax_total,
        total=total,
        discount_code=discount_result["applied_codes"][0]["code"] if discount_result["applied_codes"] else None,
        payment=payment,
    )

    return CheckoutResult(
        order=order,
        payment=payment,
        breakdown={
            "subtotal": subtotal,
            "discount_total": discount_total,
            "discounted_subtotal": discounted_subtotal,
            "tax_total": tax_total,
            "total": total,
            "applied_codes": discount_result["applied_codes"],
        },
    )